import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"LinkedQL — Universal Database Contract for Applications & Agents","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),o={name:"overview.md"};function i(r,e,l,c,p,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="linkedql-—-universal-database-contract-for-applications-agents" tabindex="-1">LinkedQL <br>— Universal Database Contract for Applications &amp; Agents <a class="header-anchor" href="#linkedql-—-universal-database-contract-for-applications-agents" aria-label="Permalink to &quot;LinkedQL &lt;br&gt;— Universal Database Contract for Applications &amp; Agents&quot;">​</a></h1><p><strong>Welcome to the docs.</strong> This page is the conceptual narrative of LinkedQL — the core thinking, the problem space it addresses, and the architectural model it introduces. It is not a setup guide. If you&#39;re here to get running, jump straight to the <a href="/guides">Core Guides</a>.</p><hr><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>LinkedQL is in active development. The core query model and interfaces are stabilizing and backed by 1,200+ tests. MySQL/MariaDB live query support is still in progress. Feedback, issues, and PRs are welcome — see <a href="https://github.com/linked-db/linked-ql#-contributing" target="_blank" rel="noreferrer">Contributing</a>.</p></div><hr><h2 id="what-is-linkedql" tabindex="-1">What is LinkedQL? <a class="header-anchor" href="#what-is-linkedql" aria-label="Permalink to &quot;What is LinkedQL?&quot;">​</a></h2><p>LinkedQL is a new query primitive that lets developers express the application&#39;s logical, runtime, and lifecycle contract with the database directly within the query. It achieves this through a small set of additions to SQL — an object-relational syntax, live queries and sync capabilities, and an automatic versioning system.</p><p>While the traditional approach achieves this through an entire data stack and ongoing developer effort, LinkedQL composes these behaviours natively in SQL.</p><p><strong>Before:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>Application  ⇄  [ ORM                     ]  ⇄  Database</span></span>
<span class="line"><span>                [ Realtime Infrastructure ]</span></span>
<span class="line"><span>                [ Sync Infrastructure     ]</span></span>
<span class="line"><span>                [ Manual Lifecycle        ]</span></span>
<span class="line"><span>                  Coordination</span></span></code></pre></div><p><strong>After:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>Application  ⇄  [ db.query(sql)           ]  ⇄  Database</span></span></code></pre></div><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><ol><li><p><strong>Automatic logical alignment via an object-relational syntax (<a href="/lang/json-literals">JSON Literals</a>, <a href="/lang/deeprefs">DeepRefs</a>):</strong> The structure that the application expects is expressed directly in the query — codifying the logical contract between storage and application. This eliminates the ORM and traditional data assembly line.</p></li><li><p><strong>Automatic runtime convergence via live queries and sync (<a href="/realtime/live-queries">Live Queries</a>, <a href="/flashql/federation-and-sync">Sync</a>):</strong> In just a mode switch: <code>{ live: true }</code>, the query itself becomes an automatic subscription for realtime applications. In just another mode switch, the database itself becomes the sync engine for offline-first applications. This eliminates the traditional state engineering exercise — Realtime infrastructure, Sync infrastructure.</p></li><li><p><strong>Automatic lifecycle convergence via semantic versioning (<a href="/lang/version-binding">Version Binding</a>):</strong> Schemas are automatically versioned as they evolve. Queries explicitly define their version assumptions. Both structures evolve in lockstep under a shared version model — instead of through manual coordination. This makes versioning a first-class property of the query itself.</p></li></ol><h3 id="result-sql-as-state-machine" tabindex="-1">Result: <em>SQL as State Machine</em> <a class="header-anchor" href="#result-sql-as-state-machine" aria-label="Permalink to &quot;Result: _SQL as State Machine_&quot;">​</a></h3><p>A paradigm shift in how the application contract is expressed and enforced: from a choreography of tools, compensatory layers, and purpose-built infrastructure to a self-enforcing contract at the query boundary.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;"> // or: MySQLClient | FlashQL | EdgeClient</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// A live query — structured output, relationship traversal, in plain SQL</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> liveResult </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT {</span></span>
<span class="line"><span style="color:#C3E88D;">    id,</span></span>
<span class="line"><span style="color:#C3E88D;">    profile: { name, email },</span></span>
<span class="line"><span style="color:#C3E88D;">    parent: parent_user ~&gt; { name, email }</span></span>
<span class="line"><span style="color:#C3E88D;">  } FROM users;</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// liveResult.rows updates automatically as the database changes —</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// no realtime infrastructure, no separate subscription system</span></span></code></pre></div><hr><h2 id="design-architecture" tabindex="-1">Design &amp; Architecture <a class="header-anchor" href="#design-architecture" aria-label="Permalink to &quot;Design &amp; Architecture&quot;">​</a></h2><p>LinkedQL is not a replacement for the database. It is <em>a programming contract for a database</em> — PostgreSQL, MySQL/MariaDB. In this model, <strong>developers use LinkedQL as a universal database contract across storage backends.</strong></p><h3 id="runtime-extensions" tabindex="-1">Runtime Extensions <a class="header-anchor" href="#runtime-extensions" aria-label="Permalink to &quot;Runtime Extensions&quot;">​</a></h3><p>Modern applications also increasingly need database capabilities in places where a traditional database server is impractical, unavailable, or simply the wrong abstraction. LinkedQL extends naturally into those environments through two built-in primitives:</p><ul><li><strong>A cross-runtime primitive: <a href="/guides/edge">the Edge Protocol</a></strong></li><li><strong>A local primitive: <a href="/flashql">FlashQL</a></strong></li></ul><p>Through these primitives, developers use LinkedQL as <strong>a universal database contract across runtime boundaries — server, browser, worker, edge.</strong></p><p><strong>Before:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>1. Server-Side Application  ⇄  [ ORM                     ]  ⇄  Database</span></span>
<span class="line"><span>                               [ Realtime Infrastructure ]</span></span>
<span class="line"><span>                               [ Sync Infrastructure     ]</span></span>
<span class="line"><span>                               [ Manual Lifecycle        ]</span></span>
<span class="line"><span>                                 Coordination</span></span>
<span class="line"><span>2. Client-Side Application  ⇄  [ API Server              ]  ⇄  Database</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>3. Local-First Application  ⇄  [ db.query(sql)           ]  ⇄  Database</span></span>
<span class="line"><span>                                                        (Local SQLite, PGLite, etc.)</span></span></code></pre></div><p><strong>After:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>                                      [ 1. Native Connection + Database ]</span></span>
<span class="line"><span>Application  ⇄  [ db.query(sql) ]  ⇄  [ 2. Edge Protocol + Database     ]</span></span>
<span class="line"><span>                                      [ 3. Local Database (FlashQL)     ]</span></span></code></pre></div><h3 id="how-it-works-1" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works-1" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Primitive</th><th>Architectural Execution</th></tr></thead><tbody><tr><td><strong>The Edge Protocol</strong></td><td>(Cross-Runtime Primitive) Exposes remote databases directly to application runtimes across network or worker boundaries — where the traditional approach keeps the database behind REST/GraphQL servers. By making the database directly queryable from anywhere, the Edge Protocol erases both the client/server boundary and the traditional SQL/API server split. <em><strong><a href="/guides/edge">See the Edge Guide</a></strong></em></td></tr><tr><td><strong>FlashQL</strong></td><td>(Local SQL Engine) A purpose-built, embeddable, lightweight local database engine that implements the full LinkedQL contract. FlashQL works anywhere JavaScript does — server, browser, worker, edge. This removes the network dependency for local-first and offline-first applications. <em><strong><a href="/flashql">Meet FlashQL</a></strong></em></td></tr></tbody></table><h3 id="result-a-universal-database-contract" tabindex="-1">Result: <em>A Universal Database Contract</em> <a class="header-anchor" href="#result-a-universal-database-contract" aria-label="Permalink to &quot;Result: _A Universal Database Contract_&quot;">​</a></h3><p>In addition to changing <em>how the application contract is expressed and enforced</em> — from manual to automatic — LinkedQL also changes <em>how the application deals with the various database engineering details</em> — engine, dialect, topology — from implementation-specific coupling to a universal contract that everything else sits behind, while the application maintains consistent logic.</p><p>Combined, applications get a universal, self-governed database contract that automatically resolves all the moving parts — from logical, runtime, and lifecycle convergence, to engine, dialect, and topology details.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;">// The same interface — across backends and evironments</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">     // PostgreSQL        – runs on the server</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> MySQLClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">  // MySQL / MariaDB   – runs on the server</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">      // Local database    – runs anywhere: server, browser, worker, edge</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span><span style="color:#676E95;font-style:italic;">   // Remote querying   – runs anywhere: server, browser, worker, edge</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Consistent application logic</span></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT { id, profile: { name, email } } FROM users;</span><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="scenarios" tabindex="-1">Scenarios <a class="header-anchor" href="#scenarios" aria-label="Permalink to &quot;Scenarios&quot;">​</a></h2><h3 id="scenario-1-edge-protocol-standardizing-data-apis-on-sql" tabindex="-1">Scenario 1: <em>Edge Protocol Standardizing Data APIs on SQL.</em> <a class="header-anchor" href="#scenario-1-edge-protocol-standardizing-data-apis-on-sql" aria-label="Permalink to &quot;Scenario 1: _Edge Protocol Standardizing Data APIs on SQL._&quot;">​</a></h3><p>A team running a Node.js backend exposes a GraphQL API to their frontend. Every new feature request triggers a backend change: new resolvers, schema updates, redeployments. The frontend team is bottlenecked on the backend team&#39;s capacity. After adopting LinkedQL, the frontend queries the database directly through the Edge Protocol using plain SQL — with live updates replacing their Apollo subscription setup. The GraphQL layer is retired. The backend team stops being a bottleneck. The frontend team has full querying power at the same <code>db.query()</code> interface — with live queries, sync, and version safety included.</p><h3 id="scenario-2-flashql-as-state-machine-for-agents" tabindex="-1">Scenario 2: <em>FlashQL as State Machine for Agents.</em> <a class="header-anchor" href="#scenario-2-flashql-as-state-machine-for-agents" aria-label="Permalink to &quot;Scenario 2: _FlashQL as State Machine for Agents._&quot;">​</a></h3><p>An AI agent framework needs structured, persistent, and synchronizable memory across sessions. The agent uses FlashQL as its local state store — writing context in plain SQL, subscribing live to changes in its working memory as its reasoning evolves, and syncing state deterministically to a cloud Postgres instance between runs. When a reasoning step produces state that needs to be undone, the agent issues a rollback. FlashQL converges local and remote state without orchestration code. The agent&#39;s entire state lifecycle — read, write, subscribe, sync, rollback — is a single SQL interface. No vector database, no separate memory middleware, no custom sync logic.</p><hr><h2 id="why-linkedql" tabindex="-1">Why LinkedQL <a class="header-anchor" href="#why-linkedql" aria-label="Permalink to &quot;Why LinkedQL&quot;">​</a></h2><p>Multiple shifts are setting a new standard for modern applications and widening the gap between application requirements and traditional database assumptions:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Shift</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:left;">Compensatory infrastructure layers around databases are continuing to accumulate</td><td style="text-align:right;">Engineering overhead reaching a visible ceiling</td></tr><tr><td style="text-align:left;">Applications now span realtime, offline-first, and distributed runtimes by default</td><td style="text-align:right;">Coordination complexity compounding beyond what point solutions handle cleanly</td></tr><tr><td style="text-align:left;">AI agents require persistent, structured, versionable state to operate reliably</td><td style="text-align:right;">A new infrastructure category forming with no established standard</td></tr></tbody></table><p>This future has arrived inheriting old foundations. LinkedQL&#39;s timing reflects a moment where the new requirements are failing so visibly on old foundations that the question is no longer whether the layer changes — it&#39;s what replaces it.</p><h3 id="the-failure-modes" tabindex="-1">The Failure Modes <a class="header-anchor" href="#the-failure-modes" aria-label="Permalink to &quot;The Failure Modes&quot;">​</a></h3><p>A database and an application are two divergent systems that share little in common. Every integration, across every team, forces a relationship that suffers the same failure modes: <strong>logical misalignment</strong>, <strong>runtime divergence</strong>, and <strong>lifecycle drift</strong>.</p><p>How the contract barely holds across all of the moving parts remains largely a developer&#39;s effort — a choreography of tools, compensatory layers, and purpose-built infrastructure.</p><h3 id="failure-mode-01-logical-misalignment" tabindex="-1">Failure Mode 01: Logical Misalignment <a class="header-anchor" href="#failure-mode-01-logical-misalignment" aria-label="Permalink to &quot;Failure Mode 01: Logical Misalignment&quot;">​</a></h3><p>The storage layer and application layer represent things in fundamentally different ways. Developers compensate through object-relational mapping, post-processing pipelines, and multiple query roundtrips to reshape relational data into application structures.</p><blockquote><p><strong>Compensation Cost:</strong> A data assembly line for every fetch operation.</p></blockquote><h3 id="failure-mode-02-runtime-divergence" tabindex="-1">Failure Mode 02: Runtime Divergence <a class="header-anchor" href="#failure-mode-02-runtime-divergence" aria-label="Permalink to &quot;Failure Mode 02: Runtime Divergence&quot;">​</a></h3><p>Data evolves at runtime. Applications must reflect that in realtime or drift out of sync with reality. Developers compensate by building subscription systems around the database to drive application state. For offline-first applications, the problem compounds — those additionally require dedicated sync engines to handle asynchronous writes and eventual convergence.</p><blockquote><p><strong>Compensation Cost:</strong> Complex state engineering for realtime and offline-first applications.</p></blockquote><h3 id="failure-mode-03-lifecycle-drift" tabindex="-1">Failure Mode 03: Lifecycle Drift <a class="header-anchor" href="#failure-mode-03-lifecycle-drift" aria-label="Permalink to &quot;Failure Mode 03: Lifecycle Drift&quot;">​</a></h3><p>Schema and code are never truly finished. The two also don&#39;t evolve together. Developers have to stay ahead of the drift, or production breaks. With no shared contract or intelligence layer between the two moving targets, developers compensate through manual coordination as the application evolves.</p><blockquote><p><strong>Compensation Cost:</strong> Manual coordination work — on a best-effort basis.</p></blockquote><h3 id="impact" tabindex="-1">Impact <a class="header-anchor" href="#impact" aria-label="Permalink to &quot;Impact&quot;">​</a></h3><p>This is a fundamental inefficiency in how software is built, costing teams everywhere lost productivity, architectural and operational overheads, and significant recurring spend.</p><p>But this is not a bug in any specific tool. It is the predictable, systemic outcome of running two completely divergent systems without a shared contract.</p><p><strong>Building from where the problem space converges is the LinkedQL core differentiator.</strong></p><hr><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>With the conceptual model in context, the next step is getting started.</p><p>The <a href="/guides">Core Guides</a> take you through from installation to running your first query.</p><h2 id="your-map-to-the-docs" tabindex="-1">Your Map to the Docs <a class="header-anchor" href="#your-map-to-the-docs" aria-label="Permalink to &quot;Your Map to the Docs&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Area</th><th style="text-align:left;">What it covers</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">Core Guides</td><td style="text-align:left;">From basic setup to first queries, to more comprehensive guides</td><td style="text-align:left;"><a href="/guides">Core Guides</a></td></tr><tr><td style="text-align:left;">Core API</td><td style="text-align:left;">Core API contract — the interface and query model</td><td style="text-align:left;"><a href="/api">Core API</a></td></tr><tr><td style="text-align:left;">Language Surface</td><td style="text-align:left;">The LinkedQL language surface (JSON Literals, DeepRefs, etc.)</td><td style="text-align:left;"><a href="/lang">Language Surface</a></td></tr><tr><td style="text-align:left;">Realtime Capabilities</td><td style="text-align:left;">Live queries and subscription model</td><td style="text-align:left;"><a href="/realtime">Realtime Capabilities</a></td></tr><tr><td style="text-align:left;">FlashQL</td><td style="text-align:left;">LinkedQL&#39;s embeddable SQL engine for local execution, federation, and sync</td><td style="text-align:left;"><a href="/flashql">FlashQL</a></td></tr></tbody></table>`,68)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
